class ScienceSimulation {
  constructor(container, initialInputs) {
    this.container = container;
    this.canvas = document.createElement('canvas');
    this.ctx = this.canvas.getContext('2d');
    this.container.appendChild(this.canvas);
    this.resize();
    window.addEventListener('resize', () => this.resize());
  }

  resize() {
    this.canvas.width = this.container.clientWidth;
    this.canvas.height = this.container.clientHeight;
  }

  getSteps(inputs) {
    const pgc = inputs.bp * 0.6;
    const pbs = 15;
    const nfp = pgc - pbs - inputs.colloid;
    const gfr = Math.max(0, inputs.kf * nfp);
    const glucoseFiltered = (gfr * inputs.glucose) / 100;
    const glucoseReabsorbed = Math.min(glucoseFiltered, 375); // Transport maximum TmG approx 375mg/min
    const glycosuria = glucoseFiltered > 375;

    return [
      {
        title: "The Glomerulus: Filtration",
        description: `Blood enters the glomerulus. With a MAP of **${inputs.bp} mmHg**, the capillary pressure ($P_{GC}$) is approx **${pgc.toFixed(1)} mmHg**. \n\nNet Filtration Pressure: $${pgc.toFixed(1)} - ${pbs} - ${inputs.colloid} = ${nfp.toFixed(1)}$ mmHg. \n\nCalculated GFR: **${gfr.toFixed(1)} mL/min**.`
      },
      {
        title: "Proximal Convoluted Tubule (PCT)",
        description: `The PCT reabsorbs ~65% of water and 100% of glucose (up to the renal threshold). \n\nGlucose filtered: **${glucoseFiltered.toFixed(1)} mg/min**. \n\n${glycosuria ? "**Warning:** Glucose exceeds transport maximum ($T_m$). Glucose will appear in urine (Glycosuria)." : "All glucose is successfully reabsorbed."}`
      },
      {
        title: "Loop of Henle",
        description: "The descending limb reabsorbs water, while the thick ascending limb actively pumps out salts ($Na^+/K^+/2Cl^-$), creating the medullary osmotic gradient."
      },
      {
        title: "Distal Tubule & Collecting Duct",
        description: `Final water reabsorption is regulated by ADH (Vasopressin). At **${inputs.adh}%** ADH levels, the urine will be ${inputs.adh > 70 ? "highly concentrated" : inputs.adh < 30 ? "very dilute" : "moderately concentrated"}.`
      }
    ];
  }

  drawNephronPath(ctx, scale) {
    ctx.beginPath();
    ctx.strokeStyle = '#f59e0b';
    ctx.lineWidth = 12 * scale;
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';

    // Bowman's Capsule
    ctx.arc(150 * scale, 150 * scale, 40 * scale, 0.2 * Math.PI, 1.8 * Math.PI, true);

    // PCT
    ctx.bezierCurveTo(200 * scale, 100 * scale, 250 * scale, 200 * scale, 300 * scale, 150 * scale);

    // Loop of Henle
    ctx.lineTo(300 * scale, 450 * scale);
    ctx.arc(325 * scale, 450 * scale, 25 * scale, Math.PI, 0, true);
    ctx.lineTo(350 * scale, 150 * scale);

    // DCT
    ctx.bezierCurveTo(400 * scale, 100 * scale, 450 * scale, 200 * scale, 500 * scale, 150 * scale);

    // Collecting Duct
    ctx.lineTo(500 * scale, 550 * scale);
    ctx.stroke();
  }

  render(inputs, stepIndex) {
    const { ctx, canvas } = this;
    const w = canvas.width;
    const h = canvas.height;
    const scale = Math.min(w / 600, h / 600);

    ctx.clearRect(0, 0, w, h);
    ctx.fillStyle = '#0f172a';
    ctx.fillRect(0, 0, w, h);

    // Draw Nephron Structure
    this.drawNephronPath(ctx, scale);

    // Glomerulus (Capillary Tuft)
    ctx.beginPath();
    ctx.strokeStyle = '#ef4444';
    ctx.lineWidth = 4 * scale;
    for(let i=0; i<5; i++) {
        ctx.arc(140 * scale + (i*4), 150 * scale, 20 * scale, 0, Math.PI * 2);
    }
    ctx.stroke();

    // Afferent/Efferent Arterioles
    ctx.beginPath();
    ctx.moveTo(50 * scale, 130 * scale);
    ctx.lineTo(120 * scale, 140 * scale);
    ctx.moveTo(120 * scale, 160 * scale);
    ctx.lineTo(50 * scale, 170 * scale);
    ctx.stroke();

    // Step-specific highlights
    if (stepIndex === 0) {
        // Filtration arrows
        ctx.fillStyle = '#3b82f6';
        for(let i=0; i<3; i++) {
            this.drawArrow(ctx, 150*scale, 150*scale, 190*scale, 150*scale + (i-1)*20*scale);
        }
        ctx.fillStyle = '#f8fafc';
        ctx.font = `${14 * scale}px sans-serif`;
        ctx.fillText("Filtration (GFR)", 160*scale, 110*scale);
    }

    if (stepIndex === 1) {
        // PCT Reabsorption
        ctx.fillStyle = '#10b981';
        this.drawArrow(ctx, 250*scale, 150*scale, 250*scale, 80*scale);
        ctx.fillText("Reabsorption", 220*scale, 70*scale);
        if (inputs.glucose > 180) {
            ctx.fillStyle = '#f43f5e';
            ctx.fillText("Glucose Loss!", 280*scale, 180*scale);
        }
    }

    if (stepIndex === 2) {
        // Loop of Henle
        ctx.fillStyle = '#3b82f6';
        this.drawArrow(ctx, 290*scale, 300*scale, 240*scale, 300*scale); // Water out
        ctx.fillStyle = '#f59e0b';
        this.drawArrow(ctx, 360*scale, 300*scale, 410*scale, 300*scale); // Salt out
        ctx.fillStyle = '#f8fafc';
        ctx.fillText("H2O", 220*scale, 305*scale);
        ctx.fillText("NaCl", 420*scale, 305*scale);
    }

    if (stepIndex === 3) {
        // Collecting Duct
        const urineColor = inputs.adh > 70 ? '#f59e0b' : '#fef08a';
        ctx.fillStyle = urineColor;
        ctx.beginPath();
        ctx.arc(500*scale, 530*scale, 10*scale, 0, Math.PI*2);
        ctx.fill();
        ctx.fillStyle = '#f8fafc';
        ctx.fillText(inputs.adh > 70 ? "Concentrated Urine" : "Dilute Urine", 450*scale, 570*scale);
    }
  }

  drawArrow(ctx, fromx, fromy, tox, toy) {
    const headlen = 10;
    const dx = tox - fromx;
    const dy = toy - fromy;
    const angle = Math.atan2(dy, dx);
    ctx.beginPath();
    ctx.moveTo(fromx, fromy);
    ctx.lineTo(tox, toy);
    ctx.lineTo(tox - headlen * Math.cos(angle - Math.PI / 6), toy - headlen * Math.sin(angle - Math.PI / 6));
    ctx.moveTo(tox, toy);
    ctx.lineTo(tox - headlen * Math.cos(angle + Math.PI / 6), toy - headlen * Math.sin(angle + Math.PI / 6));
    ctx.stroke();
  }
}
